steps.content:
{
  "success": true,
  "data": "{
  "database": "ercot_db",
  "query": "\nSELECT \n    date_trunc('hour', timestamp) as hour,\n    AVG(lmp) as avg_lmp\nFROM ercot_lmp \nWHERE zone_name = 'west' \n    AND zone_type = 'hub' \n    AND is_day_ahead = false \n    AND timestamp >= '2010-01-01' \n    AND timestamp < '2025-01-01'\nGROUP BY date_trunc('hour', timestamp)\nORDER BY hour\nLIMIT 5\n",
  "columns": [
    "hour",
    "avg_lmp"
  ],
  "row_count": 5,
  "total_rows": 5,
  "truncated": false,
  "rows": [
    {
      "hour": "2010-12-01 00:00:00",
      "avg_lmp": 23.9025
    },
    {
      "hour": "2010-12-01 01:00:00",
      "avg_lmp": 22.395000000000003
    },
    {
      "hour": "2010-12-01 02:00:00",
      "avg_lmp": 17.3025
